//! Stoplight scheduler benchmark.
//!
//! Rust port of `foil-runtime/bench.ts`. Drives 50 tasks through a single
//! 1-slot bottleneck with 8 µs of "service work" (busy-spin) and compares
//! two schedulers:
//!
//! * `naive_fork`     -- everyone fires immediately, head-of-line blocking
//!                       on the bottleneck.
//! * `stoplight_fork` -- each task carries its own Stoplight, waits for
//!                       its earliest green tick, then crosses.
//!
//! The TS reference measured a 9.4x p99 win on this workload. The Rust
//! definition of done requires >= 5x p99 improvement.
//!
//! Run:   cargo bench --bench stoplight
//!
//! Output: p50/p95/p99/max-queue/green-hit-rate for both schedulers.
//!
//! Note: this bench's "tick" is one microsecond, not one millisecond.
//! Microsecond resolution is the right grain for an in-process Rust
//! scheduler that spin-waits between dispatches. The TS reference used
//! milliseconds because `setTimeout` has no sub-ms resolution.

use std::time::Duration;

use divan::black_box;
use gnosis_frf::scheduler_stoplight::{
    Chirality, LockFreeBottleneck, SchedulerStats, StoplightTask, naive_fork, stoplight_fork,
};
use gnosis_frf::stoplight::Stoplight;

fn main() {
    // Run the comparison once outside divan so we can print the numbers.
    print_comparison();
    divan::main();
}

const TASK_COUNT: u32 = 50;
const BOTTLENECK_SERVICE_US: u32 = 8;
/// One Stoplight tick == one bottleneck service interval. Staggering
/// by less than the service time fails to space arrivals -- workers
/// still contend on the gate -- so the tick has to match the
/// bottleneck's draining rate. The TS reference does the same with
/// `msPerTick = 1, BOTTLENECK_MS = 8`: each stagger of one tick
/// equals one drain of the bottleneck.
const TICK: Duration = Duration::from_micros(BOTTLENECK_SERVICE_US as u64);

/// Per the TS bench: task `i` is assigned its own unique green tick
/// inside an `N`-tick corridor cycle. We want `earliest_green_start
/// (light_i) == i`, so that task `i` fires at wall-clock `t0 + i *
/// TICK` -- one bottleneck service-interval per stagger.
///
/// Under the Lean `seesGreen` predicate (`arrivalPhase < green`,
/// `arrivalPhase = (start + travelTime + offset) mod cycle`), with
/// `travelTime = 0`, `green = 1` (one-tick window), the choice
/// `offset = (cycle - i) mod cycle` lands task `i`'s arrival phase at
/// `(i + cycle - i) mod cycle = 0 < 1` and no earlier start fits.
///
/// (The TS reference uses `offset = i * BOTTLENECK_MS` directly,
/// which works there because TS `seesGreen` separates `greenStart =
/// offset` from arrival phase. Lean folds `offset` into the phase, so
/// the inverse encoding above is the Lean equivalent.)
fn make_tasks() -> Vec<StoplightTask> {
    let cycle = TASK_COUNT;
    let green: u32 = 1;
    (0..TASK_COUNT)
        .map(|i| {
            let offset = (cycle - i) % cycle;
            let light = Stoplight::new(cycle, green, offset, 0, 1);
            StoplightTask::new(
                light,
                Chirality::Compression,
                Duration::from_micros(u64::from(BOTTLENECK_SERVICE_US)),
            )
        })
        .collect()
}

fn fmt_us(d: Duration) -> String {
    format!("{:>9.2} us", d.as_secs_f64() * 1_000_000.0)
}

/// Pick the median sample. Tail variance at sub-millisecond scales is
/// extreme on macOS (P/E core routing + thermal throttling); the
/// median across `K` runs is the honest report. `K` is odd so the
/// median is an actual sample, not an interpolation between two.
fn median_stats(mut runs: Vec<SchedulerStats>) -> SchedulerStats {
    assert!(!runs.is_empty(), "median_stats requires at least one run");
    // Rank runs by p99 latency -- the metric the DoD threshold cares
    // about. Reporting the median-p99 run gives a sample whose other
    // percentiles also tend to sit near their respective medians.
    runs.sort_by_key(|s| s.percentile(99));
    let mid = runs.len() / 2;
    runs.swap_remove(mid)
}

fn print_stats(label: &str, stats: &SchedulerStats) {
    println!("\n  {label}");
    println!("    wall-clock:     {}", fmt_us(stats.walk));
    println!("    p50 latency:    {}", fmt_us(stats.percentile(50)));
    println!("    p95 latency:    {}", fmt_us(stats.percentile(95)));
    println!("    p99 latency:    {}", fmt_us(stats.percentile(99)));
    println!("    max queue:      {:>9}", stats.max_queue);
    println!(
        "    green-hit rate: {:>8.1}%  ({}/{})",
        stats.green_hit_rate() * 100.0,
        stats.per_task.iter().filter(|t| t.green_hit).count(),
        stats.per_task.len(),
    );
}

fn print_comparison() {
    println!("\nFRF stoplight scheduler benchmark");
    println!("==================================");
    println!("Tasks:      {TASK_COUNT}");
    println!("Bottleneck: capacity=1, service={BOTTLENECK_SERVICE_US} us");
    println!(
        "Tick:       {} us  (= one service interval)",
        BOTTLENECK_SERVICE_US
    );
    println!("Stoplight:  cycle={TASK_COUNT} ticks, green=1 tick per task");

    let bottleneck = LockFreeBottleneck::new(1);

    // Warm-up: spin the pool up, drive the AIMD spin budget down by
    // hammering tight back-to-back dispatches, then let it settle.
    // Cold-call jitter (pool workers park between calls, dispatch then
    // pays unpark) dominates tail latency at this scale; the warm
    // tasks are the cheapest defense.
    let warm = make_tasks();
    for _ in 0..32 {
        let _ = naive_fork(&warm, &bottleneck);
        let _ = stoplight_fork(&warm, &bottleneck, TICK);
    }

    // Report the median of K runs so the headline numbers reflect
    // typical behavior, not the noisy fastest/slowest sample. Sub-
    // millisecond p99 is OS-jitter dominated on macOS; the median is
    // the only honest report.
    const RUNS: usize = 21;
    let mut naive_runs: Vec<SchedulerStats> = Vec::with_capacity(RUNS);
    let mut sched_runs: Vec<SchedulerStats> = Vec::with_capacity(RUNS);
    let tasks = make_tasks();
    for _ in 0..RUNS {
        naive_runs.push(naive_fork(&tasks, &bottleneck));
        sched_runs.push(stoplight_fork(&tasks, &bottleneck, TICK));
    }
    let naive = median_stats(naive_runs);
    let sched = median_stats(sched_runs);

    print_stats("NAIVE     (everyone fires at t=0)", &naive);
    print_stats("STOPLIGHT (corridor-scheduled fan-out)", &sched);

    let p99_speedup = if sched.percentile(99).as_nanos() > 0 {
        naive.percentile(99).as_nanos() as f64 / sched.percentile(99).as_nanos() as f64
    } else {
        f64::INFINITY
    };
    let p50_speedup = if sched.percentile(50).as_nanos() > 0 {
        naive.percentile(50).as_nanos() as f64 / sched.percentile(50).as_nanos() as f64
    } else {
        f64::INFINITY
    };
    let queue_reduction = if naive.max_queue > 0 {
        100.0 * (1.0 - sched.max_queue as f64 / naive.max_queue as f64)
    } else {
        0.0
    };
    println!("\n  Improvement (stoplight vs naive)");
    println!("    p50 speedup:   {p50_speedup:>6.2}x");
    println!("    p99 speedup:   {p99_speedup:>6.2}x");
    println!(
        "    max queue:     {} -> {} ({:.0}% reduction)",
        naive.max_queue, sched.max_queue, queue_reduction
    );
    println!(
        "    green-hit:     {:.0}% -> {:.0}%",
        naive.green_hit_rate() * 100.0,
        sched.green_hit_rate() * 100.0,
    );
    println!(
        "\n  DoD threshold (p99 >= 5x): {}\n",
        if p99_speedup >= 5.0 { "PASS" } else { "FAIL" }
    );
}

// ─────────────────────────────────────────────────────────────────────
// Divan bench cases. Each samples the per-call cost so the comparison
// surface across CI runs is reproducible.
// ─────────────────────────────────────────────────────────────────────

#[divan::bench(sample_count = 30, sample_size = 1)]
fn fork_race_fold_naive(bencher: divan::Bencher) {
    let tasks = make_tasks();
    let bottleneck = LockFreeBottleneck::new(1);
    bencher.bench_local(|| {
        let stats = naive_fork(&tasks, &bottleneck);
        black_box(stats);
    });
}

#[divan::bench(sample_count = 30, sample_size = 1)]
fn fork_race_fold_stoplight(bencher: divan::Bencher) {
    let tasks = make_tasks();
    let bottleneck = LockFreeBottleneck::new(1);
    bencher.bench_local(|| {
        let stats = stoplight_fork(&tasks, &bottleneck, TICK);
        black_box(stats);
    });
}
